const sourceItem =
  $('invoice__vendor--refresh-approval-data').first();

if (!sourceItem) {
  throw new Error('MANUAL_REVIEW_SOURCE_NOT_FOUND');
}

const invoice = sourceItem.json;

const normalizeText = (value) => {
  if (value === null || value === undefined) {
    return '';
  }

  return String(value)
    .replace(/\s+/g, ' ')
    .trim();
};

const normalizeUpper = (value) => {
  return normalizeText(value).toUpperCase();
};

const normalizeBoolean = (value) => {
  if (typeof value === 'boolean') {
    return value;
  }

  return [
    'true',
    '1',
    'yes',
    'active'
  ].includes(
    normalizeText(value).toLowerCase()
  );
};

const normalizeAmount = (value) => {
  if (
    value === null ||
    value === undefined ||
    value === ''
  ) {
    return null;
  }

  const normalized = String(value)
    .replace(/\s/g, '')
    .replace(/,/g, '');

  const number = Number(normalized);

  return Number.isFinite(number)
    ? number
    : null;
};

const invoiceAmount =
  normalizeAmount(invoice.total_amount);

const invoiceCurrency =
  normalizeUpper(invoice.currency);

const rules = $input.all()
  .map(item => item.json)
  .filter(rule => {
    if (!rule?.rule_id) {
      return false;
    }

    const minAmount =
      normalizeAmount(rule.min_amount);

    const maxAmount =
      normalizeAmount(rule.max_amount);

    const currencyMatches =
      normalizeUpper(rule.currency) ===
      invoiceCurrency;

    const active =
      normalizeBoolean(rule.is_active);

    const amountMatches =
      invoiceAmount !== null &&
      minAmount !== null &&
      maxAmount !== null &&
      invoiceAmount >= minAmount &&
      invoiceAmount <= maxAmount;

    return (
      currencyMatches &&
      active &&
      amountMatches
    );
  });

rules.sort((a, b) => {
  const aRange =
    normalizeAmount(a.max_amount) -
    normalizeAmount(a.min_amount);

  const bRange =
    normalizeAmount(b.max_amount) -
    normalizeAmount(b.min_amount);

  return aRange - bRange;
});

const selectedRule =
  rules.length > 0
    ? rules[0]
    : null;

const resolvedManagerId =
  normalizeText(selectedRule?.manager_id) ||
  normalizeText(invoice.manager_id);

if (!resolvedManagerId) {
  throw new Error(
    `MANAGER_ID_NOT_FOUND: ${invoice.processing_id}`
  );
}

return [
  {
    json: {
      ...invoice,

      manager_id: resolvedManagerId,
      approval_rule_id:
        selectedRule?.rule_id ?? null,
      approval_rule_count:
        rules.length,

      manager_resolved_at:
        new Date().toISOString()
    },

    binary: sourceItem.binary
  }
];

const invoice = $json;

const escapeHtml = (value) => {
  return String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
};

const formatAmount = (value) => {
  const amount = Number(value);

  if (!Number.isFinite(amount)) {
    return 'Not available';
  }

  return new Intl.NumberFormat(
    'en-US',
    {
      minimumFractionDigits: 2,
      maximumFractionDigits: 2
    }
  ).format(amount);
};

const normalizeRisks = (value) => {
  if (Array.isArray(value)) {
    return value;
  }

  return String(value ?? '')
    .split(',')
    .map(item => item.trim())
    .filter(Boolean);
};

const risks = normalizeRisks(
  invoice.risk_flags
);

const riskText = risks.length > 0
  ? risks
      .map(flag =>
        `• ${escapeHtml(flag.replace(/_/g, ' '))}`
      )
      .join('\n')
  : '• No validation warnings';

const manualReviewText =
  invoice.manual_review_decision === 'reviewed'
    ? [
        '',
        '🔍 <b>Manual review completed</b>',
        escapeHtml(
          invoice.approval_comment ||
          'The flagged invoice was reviewed.'
        )
      ].join('\n')
    : '';

const message = [
  '✅ <b>Invoice ready for final approval</b>',
  '',
  `<b>Supplier:</b> ${escapeHtml(invoice.vendor_name)}`,
  `<b>Invoice:</b> ${escapeHtml(invoice.invoice_number)}`,
  `<b>Amount:</b> ${escapeHtml(invoice.currency)} ${formatAmount(invoice.total_amount)}`,
  `<b>Invoice date:</b> ${escapeHtml(invoice.invoice_date)}`,
  `<b>Due date:</b> ${escapeHtml(invoice.due_date)}`,
  '',
  `<b>Sender verified:</b> ${invoice.sender_email_match ? 'Yes' : 'No'}`,
  `<b>Vendor verified:</b> ${invoice.vendor_found ? 'Yes' : 'No'}`,
  `<b>Bank details verified:</b> ${invoice.bank_details_match ? 'Yes' : 'No'}`,
  '',
  '<b>Validation notes:</b>',
  riskText,
  manualReviewText,
  '',
  `<b>Invoice IBAN:</b> <code>${escapeHtml(invoice.iban)}</code>`,
  `<b>Registered IBAN:</b> <code>${escapeHtml(invoice.registered_iban || 'Not available')}</code>`,
  '',
  `<a href="${escapeHtml(invoice.drive_file_url)}">Open invoice PDF</a>`,
  '',
  `<b>Processing ID:</b> <code>${escapeHtml(invoice.processing_id)}</code>`
].join('\n');

const approveCallback =
  `approve|${invoice.processing_id}`;

const rejectCallback =
  `approval_reject|${invoice.processing_id}`;

if (approveCallback.length > 64) {
  throw new Error(
    'APPROVE_CALLBACK_TOO_LONG'
  );
}

if (rejectCallback.length > 64) {
  throw new Error(
    'APPROVAL_REJECT_CALLBACK_TOO_LONG'
  );
}

return {
  json: {
    ...invoice,

    telegram_approval_message:
      message,

    approve_callback_data:
      approveCallback,

    approval_reject_callback_data:
      rejectCallback,

    approval_message_prepared_at:
      new Date().toISOString()
  },

  binary: $binary
};

const sourceItem =
  $('invoice__message--prepare-final-approval').item;

if (!sourceItem) {
  throw new Error(
    'FINAL_APPROVAL_MESSAGE_SOURCE_NOT_FOUND'
  );
}

const telegramResponse =
  $json.result ?? $json;

const telegramMessageId =
  telegramResponse.message_id ??
  telegramResponse.messageId ??
  null;

const telegramChatId =
  telegramResponse.chat?.id ??
  sourceItem.json.manager_id ??
  null;

if (!telegramMessageId) {
  throw new Error(
    'APPROVAL_TELEGRAM_MESSAGE_ID_MISSING'
  );
}

if (!telegramChatId) {
  throw new Error(
    'APPROVAL_TELEGRAM_CHAT_ID_MISSING'
  );
}

return {
  json: {
    ...sourceItem.json,

    status: 'approval_pending',
    approval_decision: 'pending',

    manager_id:
      String(telegramChatId),

    approval_telegram_message_id:
      telegramMessageId,

    approval_telegram_chat_id:
      String(telegramChatId),

    approval_requested_at:
      new Date().toISOString()
  },

  binary: sourceItem.binary
};

const approvalItem =
  $('invoice__approval--prepare-registry').item;

if (!approvalItem) {
  throw new Error(
    'APPROVAL_PENDING_RESULT_NOT_FOUND'
  );
}

return {
  json: {
    ...approvalItem.json,

    registry_updated: true,
    registry_row_number:
      $json.row_number ??
      $json.rowNumber ??
      null,

    approval_workflow_completed_at:
      new Date().toISOString()
  },

  binary: approvalItem.binary
};

const sourceItem =
  $('invoice__trigger--subworkflow').first();

if (!sourceItem) {
  throw new Error(
    'APPROVAL_SOURCE_INVOICE_NOT_FOUND'
  );
}

const invoice = sourceItem.json;

const vendors = $input.all()
  .map(item => item.json)
  .filter(vendor =>
    Boolean(vendor?.vendor_id)
  );

if (vendors.length === 0) {
  throw new Error(
    `APPROVAL_VENDOR_NOT_FOUND: ${invoice.vendor_id}`
  );
}

if (vendors.length > 1) {
  throw new Error(
    `APPROVAL_VENDOR_ID_NOT_UNIQUE: ${invoice.vendor_id}`
  );
}

const vendor = vendors[0];

const normalizeText = (value) => {
  return String(value ?? '')
    .replace(/\s+/g, ' ')
    .trim();
};

const normalizeEmail = (value) => {
  return normalizeText(value)
    .toLowerCase();
};

const normalizeBankCode = (value) => {
  return normalizeText(value)
    .toUpperCase()
    .replace(/[^A-Z0-9]/g, '');
};

const senderEmailMatch =
  normalizeEmail(invoice.sender_email) ===
  normalizeEmail(vendor.contact_email);

const bankDetailsMatch =
  normalizeBankCode(invoice.iban) ===
  normalizeBankCode(vendor.iban);

return [
  {
    json: {
      ...invoice,

      vendor_found: true,
      vendor_id: vendor.vendor_id,

      registered_vendor_name:
        vendor.vendor_name,

      registered_contact_email:
        vendor.contact_email,

      registered_iban:
        vendor.iban,

      registered_currency:
        vendor.default_currency,

      sender_email_match:
        senderEmailMatch,

      bank_details_match:
        bankDetailsMatch,

      manager_id:
        vendor.manager_id ||
        invoice.manager_id ||
        '',

      approval_vendor_data_refreshed_at:
        new Date().toISOString()
    },

    binary: sourceItem.binary
  }
];
